   // ── Observability tests ────────────────────────────────────────────────

   #[test]
   fn test_forgotten_access_counter() {
       let counter = ForgottenAccessCounter::new();
       assert_eq!(counter.load(), 0);

       counter.increment();
       counter.increment();
       counter.increment();
       assert_eq!(counter.load(), 3);

       // take() returns current and resets to 0
       let val = counter.take();
       assert_eq!(val, 3);
       assert_eq!(counter.load(), 0);
   }

